#include <bits/stdc++.h>
using namespace std;
int n,m,f[1003],k;
int find(int x){
    if(f[x]==x)return x;
    return f[x]=find(f[x]);
}
void merge(int x,int y){
    int fx=find(x),fy=find(y);
    if(fx!=fy)f[fy]=fx,k--;
}
int main(){
    while(cin>>n){
        if(n==0)break;
        cin>>m;
        k=n;
        for(int i=1;i<=n;i++)f[i]=i;
        for(int i=1;i<=m;i++){
            int x,y;
            cin>>x>>y;
            merge(x,y);
        }
        cout<<k-1<<endl;
    }
    return 0;
}
